-- English Orbit verb sentence growth paths.
-- 设计原则：页面只展示“主干”和“修饰”，不展示复杂语法术语。

PRAGMA foreign_keys = ON;

CREATE TABLE IF NOT EXISTS verb_paths (
  -- 路径 ID。
  id TEXT PRIMARY KEY,
  -- 关联 verbs.id。
  verb_id TEXT NOT NULL,
  -- 冗余动词文本，方便查询和后台展示。
  verb TEXT NOT NULL,
  -- 路径标题，用于区分同一动词的不同学习路径。
  title TEXT NOT NULL,
  -- 这条路径里的中文核心含义。
  meaning_zh TEXT NOT NULL,
  -- 主干句英文。
  core_sentence_en TEXT NOT NULL,
  -- 主干句中文。
  core_sentence_zh TEXT NOT NULL,
  -- 最终成品句英文，通常等于 steps_json 最后一步的 sentence_en。
  full_sentence_en TEXT NOT NULL,
  -- 最终成品句中文。
  full_sentence_zh TEXT NOT NULL,
  -- 开发者学习场景，比如 code、debug、deploy、system。
  scene TEXT NOT NULL DEFAULT '',
  -- 固定结构的句子生长步骤 JSON。
  steps_json TEXT NOT NULL CHECK (json_valid(steps_json)),
  -- 创建时间。
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  -- 更新时间。
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,

  FOREIGN KEY (verb_id) REFERENCES verbs(id) ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS idx_verb_paths_verb_id ON verb_paths(verb_id);
CREATE INDEX IF NOT EXISTS idx_verb_paths_verb ON verb_paths(verb);
CREATE INDEX IF NOT EXISTS idx_verb_paths_scene ON verb_paths(scene);

INSERT INTO verb_paths (
  id,
  verb_id,
  verb,
  title,
  meaning_zh,
  core_sentence_en,
  core_sentence_zh,
  full_sentence_en,
  full_sentence_zh,
  scene,
  steps_json
) VALUES
  ('add-config-flag', 'add', 'add', 'add a config flag', '添加配置项', 'The team adds a flag.', '团队添加一个开关。', 'Before the rollout, the team adds a small flag to the config so the feature can be turned off quickly.', '上线前，团队在配置里添加一个小开关，这样功能可以快速关闭。', 'config', '[{"step_no":1,"label":"主干","sentence_en":"The team adds a flag.","sentence_zh":"团队添加一个开关。","focus_text":"The team adds a flag","note_zh":"先看最核心的动作：团队添加一个开关。","segments":[{"text":"The team adds a flag","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点对象细节","sentence_en":"The team adds a small flag to the config.","sentence_zh":"团队在配置里添加一个小开关。","focus_text":"a small flag to the config","note_zh":"这一步让“添加什么、加到哪里”更具体。","segments":[{"text":"The team adds ","kind":"core"},{"text":"a small flag to the config","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Before the rollout, the team adds a small flag to the config.","sentence_zh":"上线前，团队在配置里添加一个小开关。","focus_text":"Before the rollout","note_zh":"这一步说明动作发生在上线之前。","segments":[{"text":"Before the rollout, ","kind":"modifier"},{"text":"the team adds a small flag to the config","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"Before the rollout, the team adds a small flag to the config so the feature can be turned off quickly.","sentence_zh":"上线前，团队在配置里添加一个小开关，这样功能可以快速关闭。","focus_text":"so the feature can be turned off quickly","note_zh":"这一步说明为什么要加这个开关。","segments":[{"text":"Before the rollout, ","kind":"modifier"},{"text":"the team adds a small flag to the config","kind":"core"},{"text":" so the feature can be turned off quickly","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('adjust-timeout', 'adjust', 'adjust', 'adjust the timeout', '调整超时时间', 'The script adjusts the timeout.', '脚本调整超时时间。', 'When requests slow down, the script adjusts the timeout slightly to keep the job stable.', '当请求变慢时，脚本会稍微调整超时时间，让任务保持稳定。', 'runtime', '[{"step_no":1,"label":"主干","sentence_en":"The script adjusts the timeout.","sentence_zh":"脚本调整超时时间。","focus_text":"The script adjusts the timeout","note_zh":"先看核心：脚本在调整超时时间。","segments":[{"text":"The script adjusts the timeout","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点程度","sentence_en":"The script adjusts the timeout slightly.","sentence_zh":"脚本稍微调整超时时间。","focus_text":"slightly","note_zh":"这一步说明调整幅度不大。","segments":[{"text":"The script adjusts the timeout","kind":"core"},{"text":" slightly","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点条件","sentence_en":"When requests slow down, the script adjusts the timeout slightly.","sentence_zh":"当请求变慢时，脚本会稍微调整超时时间。","focus_text":"When requests slow down","note_zh":"这一步说明什么情况下会调整。","segments":[{"text":"When requests slow down, ","kind":"modifier"},{"text":"the script adjusts the timeout","kind":"core"},{"text":" slightly","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"When requests slow down, the script adjusts the timeout slightly to keep the job stable.","sentence_zh":"当请求变慢时，脚本会稍微调整超时时间，让任务保持稳定。","focus_text":"to keep the job stable","note_zh":"这一步说明调整是为了让任务稳定运行。","segments":[{"text":"When requests slow down, ","kind":"modifier"},{"text":"the script adjusts the timeout","kind":"core"},{"text":" slightly","kind":"modifier"},{"text":" to keep the job stable","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('analyze-logs', 'analyze', 'analyze', 'analyze recent logs', '分析日志', 'The tool analyzes the logs.', '工具分析日志。', 'After the incident, the tool analyzes the recent logs to find patterns in failed requests.', '事故发生后，工具会分析最近的日志，寻找失败请求中的规律。', 'debug', '[{"step_no":1,"label":"主干","sentence_en":"The tool analyzes the logs.","sentence_zh":"工具分析日志。","focus_text":"The tool analyzes the logs","note_zh":"先看核心：工具在分析日志。","segments":[{"text":"The tool analyzes the logs","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点对象细节","sentence_en":"The tool analyzes the recent logs.","sentence_zh":"工具分析最近的日志。","focus_text":"the recent logs","note_zh":"这一步说明分析的是最近的日志。","segments":[{"text":"The tool analyzes ","kind":"core"},{"text":"the recent logs","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"After the incident, the tool analyzes the recent logs.","sentence_zh":"事故发生后，工具会分析最近的日志。","focus_text":"After the incident","note_zh":"这一步说明分析发生在事故之后。","segments":[{"text":"After the incident, ","kind":"modifier"},{"text":"the tool analyzes the recent logs","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"After the incident, the tool analyzes the recent logs to find patterns in failed requests.","sentence_zh":"事故发生后，工具会分析最近的日志，寻找失败请求中的规律。","focus_text":"to find patterns in failed requests","note_zh":"这一步说明分析日志是为了找出失败请求里的规律。","segments":[{"text":"After the incident, ","kind":"modifier"},{"text":"the tool analyzes the recent logs","kind":"core"},{"text":" to find patterns in failed requests","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('apply-patch', 'apply', 'apply', 'apply a patch', '应用补丁', 'The worker applies the patch.', 'Worker 应用补丁。', 'During startup, the worker applies the patch to each cached response before sending it back.', '启动期间，Worker 会在返回响应前，把补丁应用到每个缓存响应上。', 'runtime', '[{"step_no":1,"label":"主干","sentence_en":"The worker applies the patch.","sentence_zh":"Worker 应用补丁。","focus_text":"The worker applies the patch","note_zh":"先看核心：Worker 应用补丁。","segments":[{"text":"The worker applies the patch","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点对象范围","sentence_en":"The worker applies the patch to each cached response.","sentence_zh":"Worker 把补丁应用到每个缓存响应上。","focus_text":"to each cached response","note_zh":"这一步说明补丁应用到哪些响应上。","segments":[{"text":"The worker applies the patch","kind":"core"},{"text":" to each cached response","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点场景","sentence_en":"During startup, the worker applies the patch to each cached response.","sentence_zh":"启动期间，Worker 把补丁应用到每个缓存响应上。","focus_text":"During startup","note_zh":"这一步说明动作发生在启动期间。","segments":[{"text":"During startup, ","kind":"modifier"},{"text":"the worker applies the patch to each cached response","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点时间","sentence_en":"During startup, the worker applies the patch to each cached response before sending it back.","sentence_zh":"启动期间，Worker 会在返回响应前，把补丁应用到每个缓存响应上。","focus_text":"before sending it back","note_zh":"这一步说明补丁应用发生在响应返回之前。","segments":[{"text":"During startup, ","kind":"modifier"},{"text":"the worker applies the patch to each cached response","kind":"core"},{"text":" before sending it back","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('build-app', 'build', 'build', 'build the app', '构建应用', 'The pipeline builds the app.', '流水线构建应用。', 'After dependencies are installed, the pipeline builds the app in a clean environment.', '依赖安装完成后，流水线会在干净环境里构建应用。', 'ci', '[{"step_no":1,"label":"主干","sentence_en":"The pipeline builds the app.","sentence_zh":"流水线构建应用。","focus_text":"The pipeline builds the app","note_zh":"先看核心：流水线构建应用。","segments":[{"text":"The pipeline builds the app","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点场景","sentence_en":"The pipeline builds the app in a clean environment.","sentence_zh":"流水线在干净环境里构建应用。","focus_text":"in a clean environment","note_zh":"这一步说明构建发生在什么环境里。","segments":[{"text":"The pipeline builds the app","kind":"core"},{"text":" in a clean environment","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点条件","sentence_en":"After dependencies are installed, the pipeline builds the app in a clean environment.","sentence_zh":"依赖安装完成后，流水线会在干净环境里构建应用。","focus_text":"After dependencies are installed","note_zh":"这一步说明构建开始前要先完成依赖安装。","segments":[{"text":"After dependencies are installed, ","kind":"modifier"},{"text":"the pipeline builds the app","kind":"core"},{"text":" in a clean environment","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('cache-result', 'cache', 'cache', 'cache the result', '缓存结果', 'The service caches the result.', '服务缓存结果。', 'To reduce repeated database reads, the service caches the result for a short time.', '为了减少重复读取数据库，服务会短时间缓存这个结果。', 'system', '[{"step_no":1,"label":"主干","sentence_en":"The service caches the result.","sentence_zh":"服务缓存结果。","focus_text":"The service caches the result","note_zh":"先看核心：服务缓存结果。","segments":[{"text":"The service caches the result","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点时间","sentence_en":"The service caches the result for a short time.","sentence_zh":"服务会短时间缓存这个结果。","focus_text":"for a short time","note_zh":"这一步说明缓存只保留一小段时间。","segments":[{"text":"The service caches the result","kind":"core"},{"text":" for a short time","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点目的","sentence_en":"To reduce repeated database reads, the service caches the result for a short time.","sentence_zh":"为了减少重复读取数据库，服务会短时间缓存这个结果。","focus_text":"To reduce repeated database reads","note_zh":"这一步说明为什么要缓存。","segments":[{"text":"To reduce repeated database reads, ","kind":"modifier"},{"text":"the service caches the result","kind":"core"},{"text":" for a short time","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('create-project', 'create', 'create', 'create a project', '创建项目', 'The command creates a project.', '命令创建一个项目。', 'When a developer runs the command, it creates a new project with a simple default structure.', '当开发者运行这个命令时，它会创建一个带有简单默认结构的新项目。', 'cli', '[{"step_no":1,"label":"主干","sentence_en":"The command creates a project.","sentence_zh":"命令创建一个项目。","focus_text":"The command creates a project","note_zh":"先看核心：命令创建项目。","segments":[{"text":"The command creates a project","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点对象细节","sentence_en":"The command creates a new project.","sentence_zh":"命令创建一个新项目。","focus_text":"a new project","note_zh":"这一步说明创建的是一个新项目。","segments":[{"text":"The command creates ","kind":"core"},{"text":"a new project","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点内容","sentence_en":"The command creates a new project with a simple default structure.","sentence_zh":"命令创建一个带有简单默认结构的新项目。","focus_text":"with a simple default structure","note_zh":"这一步说明新项目自带什么内容。","segments":[{"text":"The command creates a new project","kind":"core"},{"text":" with a simple default structure","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点条件","sentence_en":"When a developer runs the command, it creates a new project with a simple default structure.","sentence_zh":"当开发者运行这个命令时，它会创建一个带有简单默认结构的新项目。","focus_text":"When a developer runs the command","note_zh":"这一步说明什么时候会创建项目。","segments":[{"text":"When a developer runs the command, ","kind":"modifier"},{"text":"it creates a new project","kind":"core"},{"text":" with a simple default structure","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('debug-issue', 'debug', 'debug', 'debug an issue', '调试问题', 'The engineer debugs the issue.', '工程师调试这个问题。', 'After the error appears again, the engineer debugs the issue by checking the request payload.', '错误再次出现后，工程师通过检查请求数据来调试这个问题。', 'debug', '[{"step_no":1,"label":"主干","sentence_en":"The engineer debugs the issue.","sentence_zh":"工程师调试这个问题。","focus_text":"The engineer debugs the issue","note_zh":"先看核心：工程师在调试问题。","segments":[{"text":"The engineer debugs the issue","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点方式","sentence_en":"The engineer debugs the issue by checking the request payload.","sentence_zh":"工程师通过检查请求数据来调试这个问题。","focus_text":"by checking the request payload","note_zh":"这一步说明工程师用什么方式调试。","segments":[{"text":"The engineer debugs the issue","kind":"core"},{"text":" by checking the request payload","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"After the error appears again, the engineer debugs the issue by checking the request payload.","sentence_zh":"错误再次出现后，工程师通过检查请求数据来调试这个问题。","focus_text":"After the error appears again","note_zh":"这一步说明调试发生在错误再次出现之后。","segments":[{"text":"After the error appears again, ","kind":"modifier"},{"text":"the engineer debugs the issue","kind":"core"},{"text":" by checking the request payload","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('deploy-service', 'deploy', 'deploy', 'deploy a service', '部署服务', 'The team deploys the service.', '团队部署这个服务。', 'After the tests pass, the team deploys the service to production during a quiet window.', '测试通过后，团队会在低峰时段把服务部署到生产环境。', 'deploy', '[{"step_no":1,"label":"主干","sentence_en":"The team deploys the service.","sentence_zh":"团队部署这个服务。","focus_text":"The team deploys the service","note_zh":"先看核心：团队部署服务。","segments":[{"text":"The team deploys the service","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点位置","sentence_en":"The team deploys the service to production.","sentence_zh":"团队把服务部署到生产环境。","focus_text":"to production","note_zh":"这一步说明服务部署到哪里。","segments":[{"text":"The team deploys the service","kind":"core"},{"text":" to production","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"After the tests pass, the team deploys the service to production.","sentence_zh":"测试通过后，团队把服务部署到生产环境。","focus_text":"After the tests pass","note_zh":"这一步说明部署发生在测试通过之后。","segments":[{"text":"After the tests pass, ","kind":"modifier"},{"text":"the team deploys the service","kind":"core"},{"text":" to production","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点场景","sentence_en":"After the tests pass, the team deploys the service to production during a quiet window.","sentence_zh":"测试通过后，团队会在低峰时段把服务部署到生产环境。","focus_text":"during a quiet window","note_zh":"这一步说明团队选择在影响较小的时间窗口部署。","segments":[{"text":"After the tests pass, ","kind":"modifier"},{"text":"the team deploys the service","kind":"core"},{"text":" to production","kind":"modifier"},{"text":" during a quiet window","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('depend-on-cache', 'depend-on', 'depend on', 'depend on the cache', '依赖缓存', 'The service depends on the cache.', '这个服务依赖缓存。', 'In production, the service depends on the cache for faster responses.', '在生产环境中，这个服务依赖缓存来获得更快的响应。', 'system', '[{"step_no":1,"label":"主干","sentence_en":"The service depends on the cache.","sentence_zh":"这个服务依赖缓存。","focus_text":"The service depends on the cache","note_zh":"先看核心：服务依赖缓存。","segments":[{"text":"The service depends on the cache","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点场景","sentence_en":"In production, the service depends on the cache.","sentence_zh":"在生产环境中，这个服务依赖缓存。","focus_text":"In production","note_zh":"这一步说明这句话发生在生产环境里。","segments":[{"text":"In production, ","kind":"modifier"},{"text":"the service depends on the cache","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点目的","sentence_en":"In production, the service depends on the cache for faster responses.","sentence_zh":"在生产环境中，这个服务依赖缓存来获得更快的响应。","focus_text":"for faster responses","note_zh":"这一步说明依赖缓存带来的效果。","segments":[{"text":"In production, ","kind":"modifier"},{"text":"the service depends on the cache","kind":"core"},{"text":" for faster responses","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('handle-request', 'handle', 'handle', 'handle a request', '处理请求', 'The API handles the request.', 'API 处理请求。', 'When a user submits the form, the API handles the request and saves the validated data.', '当用户提交表单时，API 会处理请求并保存校验后的数据。', 'api', '[{"step_no":1,"label":"主干","sentence_en":"The API handles the request.","sentence_zh":"API 处理请求。","focus_text":"The API handles the request","note_zh":"先看核心：API 处理请求。","segments":[{"text":"The API handles the request","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点结果","sentence_en":"The API handles the request and saves the validated data.","sentence_zh":"API 处理请求并保存校验后的数据。","focus_text":"and saves the validated data","note_zh":"这一步说明处理请求之后还会保存数据。","segments":[{"text":"The API handles the request","kind":"core"},{"text":" and saves the validated data","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点条件","sentence_en":"When a user submits the form, the API handles the request and saves the validated data.","sentence_zh":"当用户提交表单时，API 会处理请求并保存校验后的数据。","focus_text":"When a user submits the form","note_zh":"这一步说明请求从哪里开始。","segments":[{"text":"When a user submits the form, ","kind":"modifier"},{"text":"the API handles the request","kind":"core"},{"text":" and saves the validated data","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('parse-config-file', 'parse', 'parse', 'parse a config file', '解析配置文件', 'The parser parses the file.', '解析器解析文件。', 'Before the config is loaded, the parser parses the file and reports any invalid line.', '配置加载前，解析器会解析文件，并报告任何无效的行。', 'config', '[{"step_no":1,"label":"主干","sentence_en":"The parser parses the file.","sentence_zh":"解析器解析文件。","focus_text":"The parser parses the file","note_zh":"先看核心：解析器解析文件。","segments":[{"text":"The parser parses the file","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点结果","sentence_en":"The parser parses the file and reports any invalid line.","sentence_zh":"解析器解析文件，并报告任何无效的行。","focus_text":"and reports any invalid line","note_zh":"这一步说明解析时发现问题会报告出来。","segments":[{"text":"The parser parses the file","kind":"core"},{"text":" and reports any invalid line","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Before the config is loaded, the parser parses the file and reports any invalid line.","sentence_zh":"配置加载前，解析器会解析文件，并报告任何无效的行。","focus_text":"Before the config is loaded","note_zh":"这一步说明解析发生在配置加载之前。","segments":[{"text":"Before the config is loaded, ","kind":"modifier"},{"text":"the parser parses the file","kind":"core"},{"text":" and reports any invalid line","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('process-queue', 'process', 'process', 'process the queue', '处理队列', 'The worker processes the queue.', 'Worker 处理队列。', 'Every minute, the worker processes the queue in small batches to avoid blocking new jobs.', '每分钟，Worker 会分小批处理队列，避免阻塞新的任务。', 'queue', '[{"step_no":1,"label":"主干","sentence_en":"The worker processes the queue.","sentence_zh":"Worker 处理队列。","focus_text":"The worker processes the queue","note_zh":"先看核心：Worker 处理队列。","segments":[{"text":"The worker processes the queue","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点方式","sentence_en":"The worker processes the queue in small batches.","sentence_zh":"Worker 分小批处理队列。","focus_text":"in small batches","note_zh":"这一步说明队列不是一次性全部处理。","segments":[{"text":"The worker processes the queue","kind":"core"},{"text":" in small batches","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Every minute, the worker processes the queue in small batches.","sentence_zh":"每分钟，Worker 会分小批处理队列。","focus_text":"Every minute","note_zh":"这一步说明处理队列的频率。","segments":[{"text":"Every minute, ","kind":"modifier"},{"text":"the worker processes the queue","kind":"core"},{"text":" in small batches","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"Every minute, the worker processes the queue in small batches to avoid blocking new jobs.","sentence_zh":"每分钟，Worker 会分小批处理队列，避免阻塞新的任务。","focus_text":"to avoid blocking new jobs","note_zh":"这一步说明分批处理是为了避免阻塞新任务。","segments":[{"text":"Every minute, ","kind":"modifier"},{"text":"the worker processes the queue","kind":"core"},{"text":" in small batches","kind":"modifier"},{"text":" to avoid blocking new jobs","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('release-update', 'release', 'release', 'release an update', '发布更新', 'The team releases the update.', '团队发布更新。', 'After the final review, the team releases the update with notes for affected users.', '最终审核后，团队会发布更新，并附上给受影响用户的说明。', 'release', '[{"step_no":1,"label":"主干","sentence_en":"The team releases the update.","sentence_zh":"团队发布更新。","focus_text":"The team releases the update","note_zh":"先看核心：团队发布更新。","segments":[{"text":"The team releases the update","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点内容","sentence_en":"The team releases the update with notes for affected users.","sentence_zh":"团队发布更新，并附上给受影响用户的说明。","focus_text":"with notes for affected users","note_zh":"这一步说明发布时附带了什么信息。","segments":[{"text":"The team releases the update","kind":"core"},{"text":" with notes for affected users","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"After the final review, the team releases the update with notes for affected users.","sentence_zh":"最终审核后，团队会发布更新，并附上给受影响用户的说明。","focus_text":"After the final review","note_zh":"这一步说明发布发生在最终审核之后。","segments":[{"text":"After the final review, ","kind":"modifier"},{"text":"the team releases the update","kind":"core"},{"text":" with notes for affected users","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('remove-token', 'remove', 'remove', 'remove a token', '移除敏感 token', 'The script removes the token.', '脚本移除 token。', 'Before writing the log, the script removes the token from the message to protect user data.', '写入日志前，脚本会从消息中移除 token，以保护用户数据。', 'security', '[{"step_no":1,"label":"主干","sentence_en":"The script removes the token.","sentence_zh":"脚本移除 token。","focus_text":"The script removes the token","note_zh":"先看核心：脚本移除 token。","segments":[{"text":"The script removes the token","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点来源","sentence_en":"The script removes the token from the message.","sentence_zh":"脚本从消息中移除 token。","focus_text":"from the message","note_zh":"这一步说明 token 是从哪里移除的。","segments":[{"text":"The script removes the token","kind":"core"},{"text":" from the message","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Before writing the log, the script removes the token from the message.","sentence_zh":"写入日志前，脚本会从消息中移除 token。","focus_text":"Before writing the log","note_zh":"这一步说明移除发生在写日志之前。","segments":[{"text":"Before writing the log, ","kind":"modifier"},{"text":"the script removes the token","kind":"core"},{"text":" from the message","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"Before writing the log, the script removes the token from the message to protect user data.","sentence_zh":"写入日志前，脚本会从消息中移除 token，以保护用户数据。","focus_text":"to protect user data","note_zh":"这一步说明移除 token 是为了保护用户数据。","segments":[{"text":"Before writing the log, ","kind":"modifier"},{"text":"the script removes the token","kind":"core"},{"text":" from the message","kind":"modifier"},{"text":" to protect user data","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('return-cached-value', 'return', 'return', 'return a cached value', '返回缓存值', 'The function returns a value.', '函数返回一个值。', 'If the cache has a match, the function returns the stored value without calling the database.', '如果缓存命中，函数会直接返回已存储的值，而不会调用数据库。', 'code', '[{"step_no":1,"label":"主干","sentence_en":"The function returns a value.","sentence_zh":"函数返回一个值。","focus_text":"The function returns a value","note_zh":"先看核心：函数返回一个值。","segments":[{"text":"The function returns a value","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点对象细节","sentence_en":"The function returns the stored value.","sentence_zh":"函数返回已存储的值。","focus_text":"the stored value","note_zh":"这一步说明返回的是已存储的值。","segments":[{"text":"The function returns ","kind":"core"},{"text":"the stored value","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点条件","sentence_en":"If the cache has a match, the function returns the stored value.","sentence_zh":"如果缓存命中，函数会返回已存储的值。","focus_text":"If the cache has a match","note_zh":"这一步说明什么情况下直接返回。","segments":[{"text":"If the cache has a match, ","kind":"modifier"},{"text":"the function returns the stored value","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点方式","sentence_en":"If the cache has a match, the function returns the stored value without calling the database.","sentence_zh":"如果缓存命中，函数会直接返回已存储的值，而不会调用数据库。","focus_text":"without calling the database","note_zh":"这一步说明返回缓存值时省掉了数据库调用。","segments":[{"text":"If the cache has a match, ","kind":"modifier"},{"text":"the function returns the stored value","kind":"core"},{"text":" without calling the database","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('run-tests', 'run', 'run', 'run in CI', '运行测试', 'The tests run.', '测试运行。', 'Before the branch is merged, the tests run in CI to catch broken changes early.', '分支合并前，测试会在 CI 中运行，以便尽早发现破坏性改动。', 'ci', '[{"step_no":1,"label":"主干","sentence_en":"The tests run.","sentence_zh":"测试运行。","focus_text":"The tests run","note_zh":"先看核心：测试运行。","segments":[{"text":"The tests run","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点场景","sentence_en":"The tests run in CI.","sentence_zh":"测试在 CI 中运行。","focus_text":"in CI","note_zh":"这一步说明测试在哪里运行。","segments":[{"text":"The tests run","kind":"core"},{"text":" in CI","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Before the branch is merged, the tests run in CI.","sentence_zh":"分支合并前，测试会在 CI 中运行。","focus_text":"Before the branch is merged","note_zh":"这一步说明测试发生在合并之前。","segments":[{"text":"Before the branch is merged, ","kind":"modifier"},{"text":"the tests run","kind":"core"},{"text":" in CI","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":4,"label":"加一点目的","sentence_en":"Before the branch is merged, the tests run in CI to catch broken changes early.","sentence_zh":"分支合并前，测试会在 CI 中运行，以便尽早发现破坏性改动。","focus_text":"to catch broken changes early","note_zh":"这一步说明为什么要在合并前运行测试。","segments":[{"text":"Before the branch is merged, ","kind":"modifier"},{"text":"the tests run","kind":"core"},{"text":" in CI","kind":"modifier"},{"text":" to catch broken changes early","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('throw-error', 'throw', 'throw', 'throw an error', '抛出错误', 'The function throws an error.', '函数抛出错误。', 'When the input is missing, the function throws an error with a clear message.', '当输入缺失时，函数会抛出一个带有清晰信息的错误。', 'code', '[{"step_no":1,"label":"主干","sentence_en":"The function throws an error.","sentence_zh":"函数抛出错误。","focus_text":"The function throws an error","note_zh":"先看核心：函数抛出错误。","segments":[{"text":"The function throws an error","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点内容","sentence_en":"The function throws an error with a clear message.","sentence_zh":"函数抛出一个带有清晰信息的错误。","focus_text":"with a clear message","note_zh":"这一步说明错误里带有什么信息。","segments":[{"text":"The function throws an error","kind":"core"},{"text":" with a clear message","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点条件","sentence_en":"When the input is missing, the function throws an error with a clear message.","sentence_zh":"当输入缺失时，函数会抛出一个带有清晰信息的错误。","focus_text":"When the input is missing","note_zh":"这一步说明什么情况下会抛出错误。","segments":[{"text":"When the input is missing, ","kind":"modifier"},{"text":"the function throws an error","kind":"core"},{"text":" with a clear message","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('update-cache', 'update', 'update', 'update the cache', '更新缓存', 'The client updates the cache.', '客户端更新缓存。', 'After a successful request, the client updates the cache so the page shows fresh data.', '请求成功后，客户端会更新缓存，让页面显示最新数据。', 'frontend', '[{"step_no":1,"label":"主干","sentence_en":"The client updates the cache.","sentence_zh":"客户端更新缓存。","focus_text":"The client updates the cache","note_zh":"先看核心：客户端更新缓存。","segments":[{"text":"The client updates the cache","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点时间","sentence_en":"After a successful request, the client updates the cache.","sentence_zh":"请求成功后，客户端会更新缓存。","focus_text":"After a successful request","note_zh":"这一步说明缓存什么时候更新。","segments":[{"text":"After a successful request, ","kind":"modifier"},{"text":"the client updates the cache","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点目的","sentence_en":"After a successful request, the client updates the cache so the page shows fresh data.","sentence_zh":"请求成功后，客户端会更新缓存，让页面显示最新数据。","focus_text":"so the page shows fresh data","note_zh":"这一步说明更新缓存带来的结果。","segments":[{"text":"After a successful request, ","kind":"modifier"},{"text":"the client updates the cache","kind":"core"},{"text":" so the page shows fresh data","kind":"modifier"},{"text":".","kind":"punctuation"}]}]'),
  ('validate-input', 'validate', 'validate', 'validate input', '校验输入', 'The server validates the input.', '服务器校验输入。', 'Before saving the profile, the server validates the input and rejects unsafe values.', '保存个人资料前，服务器会校验输入并拒绝不安全的值。', 'security', '[{"step_no":1,"label":"主干","sentence_en":"The server validates the input.","sentence_zh":"服务器校验输入。","focus_text":"The server validates the input","note_zh":"先看核心：服务器校验输入。","segments":[{"text":"The server validates the input","kind":"core"},{"text":".","kind":"punctuation"}]},{"step_no":2,"label":"加一点结果","sentence_en":"The server validates the input and rejects unsafe values.","sentence_zh":"服务器校验输入并拒绝不安全的值。","focus_text":"and rejects unsafe values","note_zh":"这一步说明校验后会拦下不安全的值。","segments":[{"text":"The server validates the input","kind":"core"},{"text":" and rejects unsafe values","kind":"modifier"},{"text":".","kind":"punctuation"}]},{"step_no":3,"label":"加一点时间","sentence_en":"Before saving the profile, the server validates the input and rejects unsafe values.","sentence_zh":"保存个人资料前，服务器会校验输入并拒绝不安全的值。","focus_text":"Before saving the profile","note_zh":"这一步说明校验发生在保存之前。","segments":[{"text":"Before saving the profile, ","kind":"modifier"},{"text":"the server validates the input","kind":"core"},{"text":" and rejects unsafe values","kind":"modifier"},{"text":".","kind":"punctuation"}]}]')
